<!DOCTYPE html>
<html>
<head>
  <title>Snake</title>
  <style>
    body {
      background-color: #111;
      color: #fff;
      font-family: sans-serif;
      text-align: center;
      margin: 0;
      padding: 20px;
    }
    canvas {
      display: block;
      margin: 20px auto;
      background-color: #222;
      border: 2px solid #444;
    }
    #controls {
      margin-bottom: 10px;
    }
    button {
      padding: 10px 20px;
      margin: 5px;
      font-size: 16px;
      background-color: #333;
      color: #fff;
      border: none;
      cursor: pointer;
    }
    button:hover {
      background-color: #555;
    }
    #score {
      font-size: 20px;
      margin-top: 10px;
    }
  </style>
</head>
<body>
  <div id="controls">
    <button id="start">Start</button>
    <button id="pause">Pause</button>
    <button id="reset">Reset</button>
  </div>
  <canvas id="snake" width="400" height="400"></canvas>
  <div id="score">Score: 0</div>

  <script>
    const canvas = document.getElementById('snake');
    const ctx = canvas.getContext('2d');
    const CELL_SIZE = 20;

    window.game = {
      w: 20,
      h: 20,

      reset() {
        this.snake = [
          [10, 10],
          [9, 10],
          [8, 10]
        ];
        this.direction = 'right';
        this.nextDirection = null;
        this.food = this.generateFood();
        this.aliveFlag = true;
        this.scoreValue = 0;
        document.getElementById('score').textContent = `Score: ${this.scoreValue}`;
      },

      tick() {
        if (!this.aliveFlag) return;

        const currentDir = this.direction;
        const newDir = this.nextDirection;
        if (newDir !== null) {
          if (
            !(currentDir === 'up' && newDir === 'down') &&
            !(currentDir === 'down' && newDir === 'up') &&
            !(currentDir === 'left' && newDir === 'right') &&
            !(currentDir === 'right' && newDir === 'left')
          ) {
            this.direction = newDir;
          }
          this.nextDirection = null;
        }

        const [x, y] = this.snake[0];
        let newX = x, newY = y;

        switch (this.direction) {
          case 'up': newY -= 1; break;
          case 'down': newY += 1; break;
          case 'left': newX -= 1; break;
          case 'right': newX += 1; break;
        }

        const newHead = [newX, newY];

        if (newX < 0 || newY < 0 || newX >= this.w || newY >= this.h) {
          this.aliveFlag = false;
          return;
        }

        const bodyWithoutTail = this.snake.slice(0, -1);
        if (bodyWithoutTail.some(segment => segment[0] === newHead[0] && segment[1] === newHead[1])) {
          this.aliveFlag = false;
          return;
        }

        this.snake.unshift(newHead);

        const [fx, fy] = this.food;
        if (newHead[0] === fx && newHead[1] === fy) {
          this.scoreValue++;
          document.getElementById('score').textContent = `Score: ${this.scoreValue}`;
          this.food = this.generateFood();
        } else {
          this.snake.pop();
        }
      },

      generateFood() {
        let newFood;
        do {
          newFood = [
            Math.floor(Math.random() * this.w),
            Math.floor(Math.random() * this.h)
          ];
        } while (this.snake.some(segment => segment[0] === newFood[0] && segment[1] === newFood[1]));
        return newFood;
      },

      setDir(dir) {
        this.nextDirection = dir;
      },

      setFood(x, y) {
        if (x >= 0 && x < this.w && y >= 0 && y < this.h) {
          this.food = [x, y];
          drawGame();
        }
      },

      snake() {
        return [...this.snake.map(segment => [segment[0], segment[1]])];
      },

      food() {
        return [...this.food];
      },

      alive() {
        return this.aliveFlag;
      },

      score() {
        return this.scoreValue;
      },
    };

    window.game.reset();

    function drawGame() {
      ctx.clearRect(0, 0, canvas.width, canvas.height);

      // Draw snake
      ctx.fillStyle = '#4caf50';
      for (const [x, y] of window.game.snake()) {
        ctx.fillRect(x * CELL_SIZE, y * CELL_SIZE, CELL_SIZE, CELL_SIZE);
      }

      // Draw food
      ctx.fillStyle = '#f44336';
      const [fx, fy] = window.game.food();
      ctx.fillRect(fx * CELL_SIZE, fy * CELL_SIZE, CELL_SIZE, CELL_SIZE);
    }

    drawGame();

    let gameInterval;
    let isRunning = false;

    document.getElementById('start').addEventListener('click', () => {
      if (!isRunning) {
        isRunning = true;
        gameInterval = setInterval(() => {
          window.game.tick();
          drawGame();
          if (!window.game.alive()) {
            clearInterval(gameInterval);
            isRunning = false;
          }
        }, 200);
      }
    });

    document.getElementById('pause').addEventListener('click', () => {
      clearInterval(gameInterval);
      isRunning = false;
    });

    document.getElementById('reset').addEventListener('click', () => {
      clearInterval(gameInterval);
      isRunning = false;
      window.game.reset();
      drawGame();
    });

    window.addEventListener('keydown', (e) => {
      switch(e.key) {
        case 'ArrowUp': window.game.setDir('up'); break;
        case 'ArrowDown': window.game.setDir('down'); break;
        case 'ArrowLeft': window.game.setDir('left'); break;
        case 'ArrowRight': window.game.setDir('right'); break;
      }
    });
  </script>
</body>
</html>
